<section class="section"><div class="container"><h1>Updates</h1><?php if (!empty($updates)): ?><div class="updates-list"><?php foreach ($updates as $u): ?><article><h3><?= h($u['title']) ?></h3><time><?= h(format_date($u['published_date'])) ?></time><?php if (!empty($u['excerpt'])): ?><p><?= h($u['excerpt']) ?></p><?php endif; ?></article><?php endforeach; ?></div><?php else: ?><p>No updates yet.</p><?php endif; ?></div></section>
